// RATE MONOTONIC SCHEDULING - Priority Assignment
// Shorter period = Higher priority (lower priority number)

FUNCTION CalculatePriority(task)
BEGIN
  // Priority is inversely proportional to period
  // Priority 1 = highest priority
  priority = 1 / task.period
  RETURN priority
END FUNCTION

// Example Tasks
TASKS = [
  {name: "TaskA", period: 20, execution: 5},
  {name: "TaskB", period: 50, execution: 10},
  {name: "TaskC", period: 100, execution: 25}
]

// Sort by period (ascending) to assign priorities
SORT TASKS BY period ASCENDING

// Assign priorities: shortest period gets highest priority
FOR i FROM 0 TO length(TASKS)-1 DO
  TASKS[i].priority = i + 1
END FOR

// Result: TaskA priority=1, TaskB priority=2, TaskC priority=3

#include <stdio.h>
#include <stdlib.h>

// Simple priority inheritance implementation
typedef struct {
    int taskId;
    int basePriority;
    int currentPriority;
    int holdsLock;
    struct Task* lockHolder;
} Task;

// Global lock for shared resource
typedef struct {
    Task* holder;
    int ceilingPriority;
} Mutex;

Mutex resourceLock = {NULL, 0};

// Priority Inheritance Protocol
void acquire_lock(Task* task, Mutex* lock) {
    // If lock is held, boost holder's priority
    if (lock->holder != NULL) {
        // Inheritance: raise holder's priority
        if (task->currentPriority > lock->holder->currentPriority) {
            lock->holder->currentPriority = task->currentPriority;
            printf("Priority Inheritance: Task %d priority boosted to %d\n",
                   lock->holder->taskId, lock->holder->currentPriority);
        }
    }

    // Claim the lock
    lock->holder = task;
    task->holdsLock = 1;
    task->currentPriority = lock->ceilingPriority;  // Elevate to ceiling
}

void release_lock(Task* task, Mutex* lock) {
    if (lock->holder == task) {
        lock->holder = NULL;
        task->holdsLock = 0;
        task->currentPriority = task->basePriority;  // Restore base priority
        printf("Task %d released lock, priority restored to %d\n",
               task->taskId, task->currentPriority);
    }
}

// Example usage
int main() {
    Task highTask = {1, 3, 3, 0, NULL};    // High priority (3)
    Task lowTask = {2, 1, 1, 0, NULL};     // Low priority (1)

    resourceLock.ceilingPriority = 3;  // Max priority

    printf("Initial: HighTask priority = %d, LowTask priority = %d\n",
           highTask.currentPriority, lowTask.currentPriority);

    // Low task acquires lock first
    acquire_lock(&lowTask, &resourceLock);

    // High task tries to acquire but blocked by low
    // (Low task gets priority boost from high task)
    acquire_lock(&highTask, &resourceLock);

    return 0;
}
